import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { LucideAngularModule } from 'lucide-angular';

interface Feature {
  icon: string;
  title: string;
  description: string;
}

interface Restaurant {
  name: string;
  cuisine: string;
  rating: number;
  image: string;
}

@Component({
  selector: 'app-user-home',
  standalone: true,
  imports: [CommonModule, LucideAngularModule],
  templateUrl: './home.html',
  styleUrls: ['./home.css']
})
export class Home {
  features: Feature[] = [
    {
      icon: 'utensils-crossed',
      title: 'Prenota il tuo tavolo',
      description: 'Scegli ristorante, data e ora. In pochi tap il tuo tavolo è prenotato.'
    },
    {
      icon: 'calendar-clock',
      title: 'Disponibilità in tempo reale',
      description: 'Vedi subito quali tavoli sono disponibili e scegli quello perfetto per te.'
    },
    {
      icon: 'bell-ring',
      title: 'Notifiche istantanee',
      description: 'Ricevi conferme immediate e promemoria per le tue prenotazioni.'
    },
    {
      icon: 'star',
      title: 'Recensioni verificate',
      description: 'Leggi le opinioni di altri clienti e scopri i piatti migliori.'
    },
    {
      icon: 'ticket-percent',
      title: 'Offerte esclusive',
      description: 'Accedi a promozioni e sconti riservati agli utenti dell\'app.'
    },
    {
      icon: 'history',
      title: 'Storico prenotazioni',
      description: 'Gestisci tutte le tue prenotazioni passate e future in un unico posto.'
    }
  ];

  popularRestaurants: Restaurant[] = [
    {
      name: 'La Pergola',
      cuisine: 'Cucina Italiana',
      rating: 4.8,
      image: '🍝'
    },
    {
      name: 'Sushi Zen',
      cuisine: 'Giapponese',
      rating: 4.7,
      image: '🍱'
    },
    {
      name: 'El Asador',
      cuisine: 'Spagnola',
      rating: 4.9,
      image: '🥘'
    },
    {
      name: 'Le Bistrot',
      cuisine: 'Francese',
      rating: 4.6,
      image: '🥖'
    }
  ];

  scrollToSection(sectionId: string): void {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }
}